func newNovelGraphExportCmd(flags *rootFlags) *cobra.Command {
	var clientName string
	var format string
	var limit int
	var dbPath string

	cmd := &cobra.Command{
		Use:   "export",
		Short: "Export lobbying relationship edges for graph analysis",
		Long:  "Use this for bulk network edges. Do NOT use it for a single ambiguous name; use 'entities resolve' instead.",
		Example: strings.Trim(`
  lda-gov-pp-cli graph export --client Boeing --format csv --limit 500
  lda-gov-pp-cli graph export --db ./lda.db --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			// pp:data-source local
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would export graph edges from local filings")
				return nil
			}
			if format != "" && format != "csv" && format != "json" {
				return usageErr(fmt.Errorf("--format must be csv or json"))
			}
			csvRequested := format == "csv" && !explicitJSONFlagChanged(cmd)
			ctx, cancel := boundCtx(cmd.Context(), flags)
			defer cancel()
			db, _, err := openLDAStore(ctx, cmd, flags, dbPath, "filings")
			if err != nil {
				return err
			}
			if db == nil {
				if csvRequested {
					return writeLDACSV(cmd, []map[string]any{}, []string{"source", "target", "relationship", "filing_uuid", "year", "period"})
				}
				return writeLDARows(cmd, flags, []map[string]any{}, []string{"source", "target", "relationship"})
			}
			defer db.Close()
			records, err := listLDARecords(db, "filings", 0)
			if err != nil {
				return fmt.Errorf("loading filings: %w", err)
			}
			rows := make([]map[string]any, 0)
			seen := map[string]bool{}
			addEdge := func(source, target, relationship, uuid string, year int, period string) {
				if source == "" || target == "" {
					return
				}
				key := strings.Join([]string{source, target, relationship, uuid, fmt.Sprint(year), period}, "|")
				if seen[key] || (limit > 0 && len(rows) >= limit) {
					return
				}
				seen[key] = true
				rows = append(rows, map[string]any{"source": source, "target": target, "relationship": relationship, "filing_uuid": uuid, "year": year, "period": period})
			}
			for _, rec := range records {
				client := ldaClientName(rec)
				if !ldaContainsFold(client, clientName) {
					continue
				}
				registrant := ldaRegistrantName(rec)
				uuid := ldaString(ldaAt(rec, "filing_uuid"))
				addEdge(client, registrant, "client_registrant", uuid, ldaYear(rec), ldaPeriod(rec))
				for _, issue := range ldaIssueCodes(rec) {
					addEdge(client, issue, "client_issue", uuid, ldaYear(rec), ldaPeriod(rec))
				}
				for _, activity := range ldaSlice(ldaAt(rec, "lobbying_activities")) {
					for _, lobbyist := range ldaSlice(ldaMap(activity)["lobbyists"]) {
						name := ldaNestedLobbyistName(lobbyist)
						addEdge(registrant, name, "registrant_lobbyist", uuid, ldaYear(rec), ldaPeriod(rec))
					}
					for _, entity := range ldaSlice(ldaMap(activity)["government_entities"]) {
						em := ldaMap(entity)
						name := strings.TrimSpace(ldaString(em["name"]))
						if name == "" {
							name = strings.TrimSpace(ldaString(em["government_entity_name"]))
						}
						addEdge(client, name, "client_government_entity", uuid, ldaYear(rec), ldaPeriod(rec))
					}
				}
			}
			if csvRequested {
				return writeLDACSV(cmd, rows, []string{"source", "target", "relationship", "filing_uuid", "year", "period"})
			}
			return writeLDARows(cmd, flags, rows, []string{"source", "target", "relationship", "filing_uuid", "year", "period"})
		},
	}
	cmd.Flags().StringVar(&clientName, "client", "", "client name substring to include")
	cmd.Flags().StringVar(&format, "format", "", "export format: csv or json")
	cmd.Flags().IntVar(&limit, "limit", 200, "maximum relationship edges to return")
	cmd.Flags().StringVar(&dbPath, "db", "", "SQLite database path")
	return cmd
}

func explicitJSONFlagChanged(cmd *cobra.Command) bool {
	if flag := cmd.Flag("json"); flag != nil && flag.Changed {
		return true
	}
	if root := cmd.Root(); root != nil {
		if flag := root.PersistentFlags().Lookup("json"); flag != nil && flag.Changed {
			return true
		}
	}
	return false
}
